  1	import {
  2	  FormGroup,
  3	  MenuToggle,
  4	  MenuToggleElement,
  5	  Select,
  6	  SelectList,
  7	  SelectOption,
  8	  MenuFooter,
  9	  Button,
 10	} from "@patternfly/react-core";
 11	import { ExternalLinkAltIcon } from "@patternfly/react-icons";
 12	import { useField, useFormikContext } from "formik";
 13	import * as React from "react";
 14	import { useNodeHealthCheckTranslation } from "../../../../localization/useNodeHealthCheckTranslation";
 15	import { getFieldId } from "../../../../copiedFromConsole/formik-fields/field-utils";
 16	import { getCreateInstanceUrl } from "../../../../data/model";
 17	import { RemediationTemplate } from "../../../../data/types";
 18	
 19	interface RemediationTemplateFieldProps {
 20	  fieldName: string;
 21	  kind: string;
 22	  instances: RemediationTemplate[];
 23	  loaded: boolean;
 24	  error: unknown;
 25	  autoSelectInstance: RemediationTemplate | undefined;
 26	}
 27	
 28	export const RemediationTemplateField: React.FC<
 29	  RemediationTemplateFieldProps
 30	> = ({ fieldName, kind, instances, loaded, error, autoSelectInstance }) => {
 31	  const { t } = useNodeHealthCheckTranslation();
 32	  const { setFieldValue } = useFormikContext();
 33	  const nameFieldName = `${fieldName}.template.name`;
 34	  const namespaceFieldName = `${fieldName}.template.namespace`;
 35	  const apiVersionFieldName = `${fieldName}.template.apiVersion`;
 36	  const [nameField] = useField<string>(nameFieldName);
 37	  const [namespaceField] = useField<string>(namespaceFieldName);
 38	  const [apiVersionField] = useField<string>(apiVersionFieldName);
 39	  const [isOpen, setIsOpen] = React.useState(false);
 40	  const fieldId = getFieldId(fieldName, "instance");
 41	  const prevKindRef = React.useRef<string | undefined>(kind);
 42	
 43	  // Get selected instance from name and namespace
 44	  const selectedInstance = React.useMemo(() => {
 45	    if (!nameField.value || !namespaceField.value) {
 46	      return undefined;
 47	    }
 48	    return instances.find(
 49	      (i) => i.name === nameField.value && i.namespace === namespaceField.value
 50	    );
 51	  }, [instances, nameField.value, namespaceField.value]);
 52	
 53	  // Clear instance when kind changes (FR-010)
 54	  React.useEffect(() => {
 55	    if (prevKindRef.current !== undefined && prevKindRef.current !== kind) {
 56	      setFieldValue(nameFieldName, "");
 57	      setFieldValue(namespaceFieldName, "");
 58	    }
 59	    prevKindRef.current = kind;
 60	  }, [kind, setFieldValue, nameFieldName, namespaceFieldName]);
 61	
 62	  // Auto-select if exactly one instance
 63	  React.useEffect(() => {
 64	    if (autoSelectInstance && !nameField.value && !namespaceField.value) {
 65	      setFieldValue(nameFieldName, autoSelectInstance.name);
 66	      setFieldValue(namespaceFieldName, autoSelectInstance.namespace);
 67	    }
 68	  }, [
 69	    autoSelectInstance,
 70	    nameField.value,
 71	    namespaceField.value,
 72	    setFieldValue,
 73	    nameFieldName,
 74	    namespaceFieldName,
 75	  ]);
 76	
 77	  // Disable when: no kind, loading, or error
 78	  const isDisabled = !kind || !loaded || !!error;
 79	
 80	  const onToggle = () => {
 81	    setIsOpen(!isOpen);
 82	  };
 83	
 84	  const createInstanceUrl = React.useMemo(
 85	    () => getCreateInstanceUrl(apiVersionField.value, kind),
 86	    [apiVersionField.value, kind]
 87	  );
 88	
 89	  const onSelect = (_event: unknown, selection: string | number) => {
 90	    const instance = instances.find(
 91	      (i) => `${i.namespace}/${i.name}` === selection
 92	    );
 93	    if (instance) {
 94	      setFieldValue(nameFieldName, instance.name);
 95	      setFieldValue(namespaceFieldName, instance.namespace);
 96	    }
 97	    setIsOpen(false);
 98	  };
 99	
100	  const onCreateNewInstanceClick = () => {
101	    if (createInstanceUrl) {
102	      window.open(createInstanceUrl, "_blank", "noopener,noreferrer");
103	    }
104	  };
105	
106	  const placeholder = React.useMemo(() => {
107	    if (!kind) {
108	      return t("No selected Kind");
109	    }
110	    if (!loaded) {
111	      return t("Loading");
112	    }
113	    if (error) {
114	      return t("Error loading instances");
115	    }
116	    return "";
117	  }, [kind, loaded, error, t]);
118	
119	  // Internal value format for selections prop (namespace/name)
120	  const selectedValue = selectedInstance
121	    ? `${selectedInstance.namespace}/${selectedInstance.name}`
122	    : undefined;
123	
124	  return (
125	    <FormGroup fieldId={fieldId} label={t("Instance")} isRequired>
126	      <Select
127	        id={fieldId}
128	        isOpen={isOpen}
129	        onOpenChange={setIsOpen}
130	        onOpenChangeKeys={["Escape"]}
131	        onSelect={onSelect}
132	        selections={selectedValue}
133	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
134	          <MenuToggle
135	            ref={toggleRef}
136	            onClick={onToggle}
137	            isExpanded={isOpen}
138	            isDisabled={isDisabled}
139	            isFullWidth
140	          >
141	            {selectedInstance ? selectedInstance.name : placeholder}
142	          </MenuToggle>
143	        )}
144	        maxMenuHeight="25rem"
145	        isScrollable
146	      >
147	        <SelectList>
148	          {instances.map((instance) => {
149	            const instanceValue = `${instance.namespace}/${instance.name}`;
150	            return (
151	              <SelectOption
152	                key={instanceValue}
153	                value={instanceValue}
154	                description={instance.namespace}
155	                isSelected={selectedValue === instanceValue}
156	              >
157	                {instance.name}
158	              </SelectOption>
159	            );
160	          })}
161	        </SelectList>
162	        {createInstanceUrl && loaded && (
163	          <MenuFooter>
164	            <Button
165	              variant="link"
166	              isInline
167	              onClick={onCreateNewInstanceClick}
168	              icon={<ExternalLinkAltIcon />}
169	              iconPosition="right"
170	            >
171	              {t("Create new instance")}
172	            </Button>
173	          </MenuFooter>
174	        )}
175	      </Select>
176	    </FormGroup>
177	  );
178	};

